        public function run_stock_sync() {
            WC_Atlascom_Logger::info( 'Starting Atlascom stock and price synchronization...' );

            $nbr_partition = (int) get_option( 'wc_atlascom_nbr_partition', 1 );
            if ( $nbr_partition < 1 ) {
                $nbr_partition = 1;
            }

            $enable_stock = get_option( 'wc_atlascom_enable_stock_sync' ) === 'yes';

            $synced_count = 0;
            $updated_products = 0;

            for ( $partition = 1; $partition <= $nbr_partition; $partition++ ) {
                $response = $this->api->fetch_products( $partition, $nbr_partition );
                if ( ! $response ) {
                    WC_Atlascom_Logger::error( "Failed to fetch products for partition $partition." );
                    continue;
                }

                $articles = array();
                if ( isset( $response->getListeArticlesResult->Article ) ) {
                    $articles = $response->getListeArticlesResult->Article;
                }

                if ( ! is_array( $articles ) ) {
                    if ( $articles ) {
                        $articles = array( $articles );
                    } else {
                        continue;
                    }
                }

                foreach ( $articles as $article ) {
                    $sku = isset( $article->codeArticle ) ? trim( (string) $article->codeArticle ) : '';
                    if ( empty( $sku ) ) {
                        continue;
                    }

                    $stock = isset( $article->qteStock ) ? (int) $article->qteStock : 0;
                    $price = isset( $article->prix ) ? (float) $article->prix : 0.0;

                    // Retrieve designation/libelle/nom
                    $name = '';
                    if ( isset( $article->libelle ) ) {
                        $name = trim( (string) $article->libelle );
                    } elseif ( isset( $article->designation ) ) {
                        $name = trim( (string) $article->designation );
                    } elseif ( isset( $article->nom ) ) {
                        $name = trim( (string) $article->nom );
                    }

                    $product_id = wc_get_product_id_by_sku( $sku );
                    if ( ! $product_id ) {
                        continue;
                    }

                    $product = wc_get_product( $product_id );
                    if ( ! $product ) {
                        continue;
                    }

                    $changed = false;

                    // Sync Stock
                    if ( $enable_stock ) {
                        if ( $product->get_stock_quantity() !== $stock || ! $product->get_manage_stock() ) {
                            $product->set_manage_stock( true );
                            $product->set_stock_quantity( $stock );
                            $changed = true;
                        }
                    }

                    // Sync Price
                    if ( $price > 0 && (float) $product->get_regular_price() !== $price ) {
                        $product->set_regular_price( $price );
                        $product->set_price( $price );
                        $changed = true;
                    }

                    // Sync Name (Name update fix)
                    if ( ! empty( $name ) && $product->get_name() !== $name ) {
                        $old_name = $product->get_name();
                        $product->set_name( $name );
                        WC_Atlascom_Logger::info( "SKU {$sku}: Name updated from '{$old_name}' to '{$name}'." );
                        $changed = true;
                    }

                    if ( $changed ) {
                        $product->save();
                        $updated_products++;
                    }

                    $synced_count++;
                }
            }

            update_option( 'wc_atlascom_last_sync_date', current_time( 'Y-m-d H:i:s' ) );
            WC_Atlascom_Logger::info( "Synchronization complete. Synced $synced_count articles. Updated $updated_products products in WooCommerce." );
        }
