        public function add_cron_intervals( $schedules ) {
            $schedules['every_15_mins'] = array(
                'interval' => 15 * 60,
                'display'  => __( 'Every 15 Minutes', 'wc-atlascom-sync' ),
            );
            $schedules['every_5_mins'] = array(
                'interval' => 5 * 60,
                'display'  => __( 'Every 5 Minutes', 'wc-atlascom-sync' ),
            );
            $schedules['thirty_min'] = array(
                'interval' => 30 * 60,
