            add_action( 'woocommerce_order_action_wc_atlascom_retry_sync',    array( \$this, 'process_manual_sync' ) );

            // Background event handler (Action Scheduler)
            add_action( 'wc_atlascom_sync_order_event', array( \$this, 'run_order_sync' ), 10, 1 );

            // Cron schedules & schedule management
            add_filter( 'cron_schedules', array( \$this, 'add_cron_intervals' ) );
            add_action( 'admin_init',                      array( \$this, 'check_cron_schedule' ) );
            add_action( 'wc_atlascom_retry_failed_orders', array( \$this, 'retry_failed_orders' ) );
            add_action( 'wc_atlascom_sync_new_order',      array( \$this, 'sync_scheduled_new_order' ) );

            // Only schedule the retry cron when order sync is actually enabled.
            if ( get_option( 'wc_atlascom_enable_order_sync' ) === 'yes' ) {
                if ( ! wp_next_scheduled( 'wc_atlascom_retry_failed_orders' ) ) {
                    wp_schedule_event( time(), 'every_15_mins', 'wc_atlascom_retry_failed_orders' );
                }
            }

            // UI
            add_filter( 'manage_edit-shop_order_columns',       array( \$this, 'add_sync_column' ) );
            add_action( 'manage_shop_order_posts_custom_column', array( \$this, 'render_sync_column' ), 10, 2 );
            add_action( 'add_meta_boxes',                        array( \$this, 'add_sync_meta_box' ) );
        }

        public function schedule_order_sync( \$order_id ) {
            if ( get_option( 'wc_atlascom_enable_order_sync' ) !== 'yes' ) return;

            // Skip if already synced
            if ( get_post_meta( \$order_id, '_atlascom_synced', true ) ) return;

            if ( function_exists( 'as_enqueue_async_action' ) ) {
                as_enqueue_async_action( 'wc_atlascom_sync_order_event', array( \$order_id ), 'atlascom-sync' );
                WC_Atlascom_Logger::info( \"Order #\$order_id queued for background sync via Action Scheduler.\" );
            } else {
                wp_schedule_single_event( time() + 5, 'wc_atlascom_sync_order_event', array( \$order_id ) );
                WC_Atlascom_Logger::info( \"Order #\$order_id queued for background sync via WP Cron.\" );
            }
        }

