        public function render_sync_column( \$column, \$post_id ) {
            if ( 'atlascom_sync' !== \$column ) return;
            \$is_synced = get_post_meta( \$post_id, '_atlascom_synced', true );
            if ( \$is_synced ) {
                \$date = get_post_meta( \$post_id, '_atlascom_sync_date', true );
                echo '<span style=\"color:#46b450;font-weight:bold;\">✅ Synced</span>';
                if ( \$date ) echo '<br><small style=\"color:#777;\">' . esc_html( \$date ) . '</small>';
