        public function render_sync_meta_box( \$post ) {
            \$is_synced = get_post_meta( \$post->ID, '_atlascom_synced', true );
            \$sync_date = get_post_meta( \$post->ID, '_atlascom_sync_date', true );
            \$response  = get_post_meta( \$post->ID, '_atlascom_response', true );

            \$wsdl_url = get_option( 'wc_atlascom_wsdl_url' );
            \$host     = 'Unknown';
            if ( ! empty( \$wsdl_url ) ) {
                \$parsed = parse_url( \$wsdl_url );
                \$host   = isset( \$parsed['host'] ) ? \$parsed['host'] : \$wsdl_url;
            }

            \$pharmacy_code = get_post_meta( \$post->ID, '_atlascom_pharmacy_code', true );
            if ( ! \$pharmacy_code ) {
                \$order = wc_get_order( \$post->ID );
                if ( \$order ) {
                    \$user_id = \$order->get_user_id();
                    if ( \$user_id ) \$pharmacy_code = get_user_meta( \$user_id, 'pharmacy_code', true );
                }
            }

            echo '<div class=\"wc-atlascom-sync-status\">';
            if ( \$is_synced ) {
                echo '<p style=\"color:#46b450;font-weight:bold;font-size:1.1em;margin-bottom:5px;\">✅ Synced Successfully</p>';
                echo '<p class=\"description\"><strong>Synced on:</strong> ' . esc_html( \$sync_date ) . '</p>';
                echo '<p class=\"description\"><strong>Destination Host:</strong> ' . esc_html( \$host ) . '</p>';
                if ( \$pharmacy_code ) echo '<p class=\"description\"><strong>Target Pharmacy Code:</strong> ' . esc_html( \$pharmacy_code ) . '</p>';

                \$remote_id = '';
                if ( preg_match( '/setListeCommandesResult.*?=>\\\\s*(\\\\d+)/', \$response, \$m ) ) {
                    \$remote_id = \$m[1];
                } elseif ( preg_match( '/Result.*?(\\\\d+)/', \$response, \$m ) ) {
                    \$remote_id = \$m[1];
                }
                if ( \$remote_id ) {
                    echo '<p style=\"background:#e7f5ea;padding:8px;border-radius:4px;border:1px solid #c3e6cb;\"><strong>Remote Order ID:</strong> <span style=\"font-weight:bold;\">' . esc_html( \$remote_id ) . '</span></p>';
                }
            } else {
                echo '<p style=\"color:#a00;font-weight:bold;font-size:1.1em;margin-bottom:5px;\">❌ Not Synced</p>';
                if ( \$response ) {
                    echo '<p style=\"background:#fdf3f3;padding:8px;border-radius:4px;border:1px solid #f5c6cb;color:#721c24;word-break:break-all;\"><strong>Last Error:</strong><br>' . esc_html( \$response ) . '</p>';
                }
            }
            echo '</div>';
        }

