        public function run_order_sync( \$order_id ) {
            \$order = wc_get_order( \$order_id );
            if ( ! \$order ) {
                WC_Atlascom_Logger::error( \"Order Sync: Order #\$order_id not found.\" );
                return;
            }

            if ( get_post_meta( \$order_id, '_atlascom_synced', true ) ) {
                return;
            }

            WC_Atlascom_Logger::info( \"Starting sync for Order #\$order_id...\" );

            \$date_created = \$order->get_date_created();
            \$date_c = \$date_created ? \$date_created->date( 'd/m/Y' ) : date( 'd/m/Y' );
            \$date_iso = \$date_created ? \$date_created->date( 'Y-m-d\\\\TH:i:s' ) : date( 'Y-m-d\\\\TH:i:s' );

            \$total_ht = \$order->get_total() - \$order->get_total_tax();
            \$total_ttc = \$order->get_total();
            \$total_tva = \$order->get_total_tax();

            \$commercial_code = get_option( 'wc_atlascom_code_commerciale', '000051' );

            \$user_id = \$order->get_user_id();
            if ( \$user_id ) {
                \$override_code = get_user_meta( \$user_id, 'atlascom_commercial_code', true );
                if ( ! empty( \$override_code ) ) {
                    \$commercial_code = \$override_code;
                }
            }

            \$sync_code = date( 'YmdHis' ) . \$order_id;

            \$header = array(
                'Livreur'         => '',
                'Annule'          => false,
                'Livre'           => false,
                'Partiel'         => false,
                'codeCommande'    => (int) \$order_id,
                'codeTiers'       => 'CLIENT_WEB',
                'codeClient'      => 'CLIENT_WEB',
                'dateC'           => \$date_c,
                'date'            => \$date_iso,
                'codeModeP'       => '',
                'dateEchu'        => '',
                'totalHt'         => (float) \$total_ht,
                'totalTtc'        => (float) \$total_ttc,
                'totalTva'        => (float) \$total_tva,
                'observation'     => 'WooCommerce Order #' . \$order_id,
                'remarqueDev'     => '',
                'codedeSynchcronisation' => \$sync_code,
                'remise'          => 0.0,
                'mtremise'        => 0.0,
                'codeCommerciale' => \$commercial_code,
            );

            \$lines = array();
            \$line_num = 1;

            foreach ( \$order->get_items() as \$item_id => \$item ) {
                \$product = \$item->get_product();
                if ( ! \$product ) continue;

                \$sku = \$product->get_sku();
                if ( empty( \$sku ) ) {
                    WC_Atlascom_Logger::warning( \"Order Sync: Item '{\$item->get_name()}' in Order #\$order_id is missing a SKU. Sync might be rejected.\" );
                }

                \$qty = (float) \$item->get_quantity();
                \$subtotal = (float) \$item->get_subtotal();
                \$total = (float) \$item->get_total();
                \$tax = (float) \$item->get_total_tax();

                \$pu_ht = \$qty > 0 ? (\$subtotal / \$qty) : 0;
                \$pu_ttc = \$qty > 0 ? ((\$subtotal + \$tax) / \$qty) : 0;

                \$lines[] = array(
                    'Tva'            => (float) \$tax,
                    'PlafondRM'      => 0.0,
                    'QteLivre'       => 0.0,
                    'codeLCommande'  => \$line_num,
                    'codeArticle'    => \$sku,
                    'qte'            => \$qty,
                    'prixU'          => \$pu_ht,
                    'prixTTTC'       => \$pu_ttc,
                    'codeCommande'   => (int) \$order_id,
                    'nbrPiece'       => 0.0,
                    'qteCar'         => 0.0,
                    'codedeSynchcronisation' => \$sync_code,
                    'puttc'          => \$pu_ttc,
                    'ptttc'          => (float) (\$total + \$tax),
                    'ptht'           => \$total,
                    'puht'           => \$pu_ht,
                    'remise'         => 0.0,
                    'qteGratuit'     => 0.0,
                    'codeTva'        => 0,
                    'ordre'          => \$line_num,
                    'codeUnite'      => 0,
                    'libelle'        => \$item->get_name(),
                    'TypePrix'       => '',
                    'typeLigne'      => '',
                    'codesup'        => '',
                    'qteG'           => 0.0,
                );

                \$line_num++;
            }

            \$override_code_agence = null;
            if ( \$user_id ) {
                \$pharmacy_code = get_user_meta( \$user_id, 'pharmacy_code', true );
                if ( ! empty( \$pharmacy_code ) ) {
                    \$override_code_agence = \$pharmacy_code;
                    update_post_meta( \$order_id, '_atlascom_pharmacy_code', \$pharmacy_code );
                }
            }

            \$response = \$this->api->send_orders( array( \$header ), \$lines, \$override_code_agence );

            if ( is_wp_error( \$response ) ) {
                \$error_msg = \$response->get_error_message();
                update_post_meta( \$order_id, '_atlascom_synced', 0 );
                update_post_meta( \$order_id, '_atlascom_response', \$error_msg );
                WC_Atlascom_Logger::error( \"Sync failed for Order #\$order_id: \$error_msg\" );
                \$order->add_order_note( sprintf( __( 'Atlascom Sync Failed: %s', 'wc-atlascom-sync' ), \$error_msg ) );
            } else {
                update_post_meta( \$order_id, '_atlascom_synced', 1 );
                update_post_meta( \$order_id, '_atlascom_sync_date', current_time( 'mysql' ) );
                update_post_meta( \$order_id, '_atlascom_response', print_r( \$response, true ) );
                WC_Atlascom_Logger::info( \"Sync successful for Order #\$order_id.\" );
                \$order->add_order_note( __( 'Order synced successfully to Atlascom.', 'wc-atlascom-sync' ) );
            }
        }

        public function run_stock_sync() {
            WC_Atlascom_Logger::info( 'Starting Atlascom stock, price, and product name synchronization...' );

            \$nbr_partition = (int) get_option( 'wc_atlascom_nbr_partition', 1 );
            if ( \$nbr_partition < 1 ) {
                \$nbr_partition = 1;
            }

            \$enable_stock = get_option( 'wc_atlascom_enable_stock_sync' ) === 'yes';
            \$synced_count = 0;
            \$updated_products = 0;

            for ( \$partition = 1; \$partition <= \$nbr_partition; \$partition++ ) {
                \$response = \$this->api->fetch_products( \$partition, \$nbr_partition );
                if ( ! \$response ) {
                    WC_Atlascom_Logger::error( \"Failed to fetch products for partition \$partition.\" );
                    continue;
                }

                \$articles = array();
                if ( isset( \$response->getListeArticlesResult->Article ) ) {
                    \$articles = \$response->getListeArticlesResult->Article;
                }

                if ( ! is_array( \$articles ) ) {
                    if ( \$articles ) {
                        \$articles = array( \$articles );
                    } else {
                        continue;
                    }
                }

                foreach ( \$articles as \$article ) {
                    \$sku = isset( \$article->codeArticle ) ? trim( (string) \$article->codeArticle ) : '';
                    if ( empty( \$sku ) ) {
                        continue;
                    }

                    \$stock = isset( \$article->qteStock ) ? (int) \$article->qteStock : 0;
                    \$price = isset( \$article->prix ) ? (float) \$article->prix : 0.0;

                    // Retrieve designation/libelle/nom
                    \$name = '';
                    if ( isset( \$article->libelle ) ) {
                        \$name = trim( (string) \$article->libelle );
                    } elseif ( isset( \$article->designation ) ) {
                        \$name = trim( (string) \$article->designation );
                    } elseif ( isset( \$article->nom ) ) {
                        \$name = trim( (string) \$article->nom );
                    }

                    \$product_id = wc_get_product_id_by_sku( \$sku );
                    if ( ! \$product_id ) {
                        continue;
                    }

                    \$product = wc_get_product( \$product_id );
                    if ( ! \$product ) {
                        continue;
                    }

                    \$changed = false;

                    // Sync Stock
                    if ( \$enable_stock ) {
                        if ( \$product->get_stock_quantity() !== \$stock || ! \$product->get_manage_stock() ) {
                            \$product->set_manage_stock( true );
                            \$product->set_stock_quantity( \$stock );
                            \$changed = true;
                        }
                    }

                    // Sync Price
                    if ( \$price > 0 && (float) \$product->get_regular_price() !== \$price ) {
                        \$product->set_regular_price( \$price );
                        \$product->set_price( \$price );
                        \$changed = true;
                    }

                    // Sync Name (WooCommerce product name updates from Atlascom)
                    if ( ! empty( \$name ) && \$product->get_name() !== \$name ) {
                        \$old_name = \$product->get_name();
                        \$product->set_name( \$name );
                        WC_Atlascom_Logger::info( \"[NAME UPDATE] SKU {\$sku}: Name updated from '{\$old_name}' to '{\$name}'.\" );
                        \$changed = true;
                    }

                    if ( \$changed ) {
                        \$product->save();
                        \$updated_products++;
                    }

                    \$synced_count++;
                }
            }

            update_option( 'wc_atlascom_last_sync_date', current_time( 'Y-m-d H:i:s' ) );
            WC_Atlascom_Logger::info( \"Synchronization complete. Synced \$synced_count articles. Updated \$updated_products products in WooCommerce.\" );
        }

        public function add_cron_intervals( \$schedules ) {
            \$schedules['every_15_mins'] = array(
                'interval' => 15 * 60,
                'display'  => __( 'Every 15 Minutes', 'wc-atlascom-sync' ),
            );
            \$schedules['every_5_mins'] = array(
                'interval' => 5 * 60,
                'display'  => __( 'Every 5 Minutes', 'wc-atlascom-sync' ),
            );
            \$schedules['thirty_min'] = array(
                'interval' => 30 * 60,
                'display'  => __( 'Every 30 Minutes', 'wc-atlascom-sync' ),
            );
            return \$schedules;
        }

        public function check_cron_schedule() {
            if ( get_option( 'wc_atlascom_enable_stock_sync' ) !== 'yes' ) {
                wp_clear_scheduled_hook( 'wc_atlascom_daily_stock_sync' );
                return;
            }

            \$interval = get_option( 'wc_atlascom_sync_interval', 'daily' );
            \$hook = 'wc_atlascom_daily_stock_sync';

            \$recurrence = 'daily';
            if ( \$interval === 'hourly' ) {
                \$recurrence = 'hourly';
            } elseif ( \$interval === 'thirty_min' ) {
                \$recurrence = 'thirty_min';
            } elseif ( \$interval === 'fifteen_min' ) {
                \$recurrence = 'every_15_mins';
            } elseif ( \$interval === 'five_min' ) {
                \$recurrence = 'every_5_mins';
            }

            \$next_scheduled = wp_next_scheduled( \$hook );

            if ( \$next_scheduled ) {
                \$schedule = wp_get_schedule( \$hook );
                if ( \$schedule !== \$recurrence ) {
                    wp_clear_scheduled_hook( \$hook );
                    wp_schedule_event( time(), \$recurrence, \$hook );
                    WC_Atlascom_Logger::info( \"Rescheduled stock sync to interval: \$recurrence\" );
                }
            } else {
                wp_schedule_event( time(), \$recurrence, \$hook );
                WC_Atlascom_Logger::info( \"Scheduled stock sync with interval: \$recurrence\" );
            }
        }

        public function retry_failed_orders() {
            global \$wpdb;
            \$failed_orders = \$wpdb->get_col( \"
                SELECT post_id 
                FROM {\$wpdb->postmeta} 
                WHERE meta_key = '_atlascom_synced' AND meta_value = '0'
                LIMIT 5
            \" );

            if ( ! empty( \$failed_orders ) ) {
                WC_Atlascom_Logger::info( 'Retrying sync for failed orders: ' . implode( ', ', \$failed_orders ) );
                foreach ( \$failed_orders as \$order_id ) {
                    \$this->run_order_sync( (int) \$order_id );
                }
            }
        }

        public function sync_scheduled_new_order( \$order_id ) {
            \$this->run_order_sync( \$order_id );
        }
    }
